function candidate(value) {
  if (typeof value !== "string") {
    return null;
  }

  const parsed = value.match(/^([A-Za-z][A-Za-z0-9+.-]*):\/\/(?:(?:([^@/?#]*)@))?(\[[^\]]+\]|[^:/?#]+)(?::([0-9]+))?([^?#]*)?(?:[?#].*)?$/);

  if (!parsed) {
    return null;
  }

  const result = {
    protocol: parsed[1],
    host: parsed[3]
  };

  if (parsed[2] !== undefined) {
    result.credentials = parsed[2];
  }

  if (parsed[4] !== undefined) {
    result.port = parsed[4];
  }

  if (parsed[5] !== undefined) {
    result.path = parsed[5];
  }

  return result;
}
